import { Pipe, PipeTransform, SecurityContext, inject } from '@angular/core';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';

@Pipe({
  name: 'highlight',
})
export class HighlightPipe implements PipeTransform {
  private readonly sanitizer = inject(DomSanitizer);

  transform(value: string, search: string, isHtml = false): SafeHtml {
    if (!search || !value) {
      return value;
    }

    // Escape special regex characters in search term
    const escapedSearch = search.replaceAll(
      /[.*+?^${}()|[\]\\]/g,
      String.raw`\$&`,
    );
    const re = new RegExp(`(${escapedSearch})`, 'gi');

    let highlighted: string;
    if (isHtml) {
      // Value already contains trusted HTML (pre-escaped by the caller).
      // Only highlight text nodes — matches outside of any HTML tag (avoids double-escaping).
      highlighted = value.replace(
        new RegExp(`(${escapedSearch})(?![^<]*>)`, 'gi'),
        (match) => `<mark class="highlight-match">${match}</mark>`,
      );
    } else {
      // Plain text: escape first, then highlight.
      const escapedValue = this.escapeHtml(value);
      highlighted = escapedValue.replace(
        re,
        (match) => `<mark class="highlight-match">${match}</mark>`,
      );
    }

    // Sanitize the HTML output
    const sanitized = this.sanitizer.sanitize(
      SecurityContext.HTML,
      highlighted,
    );
    return sanitized ?? value;
  }

  private escapeHtml(text: string): string {
    const map: Record<string, string> = {
      '&': '&amp;',
      '<': '&lt;',
      '>': '&gt;',
      '"': '&quot;',
      "'": '&#39;',
    };
    return text.replaceAll(/[&<>"']/g, (m) => map[m]);
  }
}
