import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  DestroyRef,
  effect,
  inject,
  input,
  OnInit,
  output,
  signal,
  TemplateRef,
  untracked,
  WritableSignal,
} from '@angular/core';
import {
  FormControl,
  ReactiveFormsModule,
  AbstractControl,
  FormsModule,
} from '@angular/forms';
import { Subscription } from 'rxjs';

import { CheckboxModule } from 'primeng/checkbox';
import { InputNumberModule } from 'primeng/inputnumber';
import { InputTextModule } from 'primeng/inputtext';
import { PasswordModule } from 'primeng/password';
import { RadioButtonModule } from 'primeng/radiobutton';
import { MultiSelectModule } from 'primeng/multiselect';
import { TextareaModule } from 'primeng/textarea';
import { DatePickerModule } from 'primeng/datepicker';
import { FileUploadModule } from 'primeng/fileupload';
import { InputMaskModule } from 'primeng/inputmask';
import { ColorPickerChangeEvent, ColorPickerModule } from 'primeng/colorpicker';
import { SliderModule } from 'primeng/slider';
import { RatingModule } from 'primeng/rating';
import { ChipModule } from 'primeng/chip';
import { EditorModule } from 'primeng/editor';
import { KeyFilterModule } from 'primeng/keyfilter';
import { MessageModule } from 'primeng/message';
import { ToggleButtonModule } from 'primeng/togglebutton';
import { KnobModule } from 'primeng/knob';
import { SelectChangeEvent, SelectModule } from 'primeng/select';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { AutoCompleteModule } from 'primeng/autocomplete';
import { ListboxModule } from 'primeng/listbox';
import { TreeSelectModule } from 'primeng/treeselect';
import { TooltipModule } from 'primeng/tooltip';
import { PopoverModule } from 'primeng/popover';

import { IconSelectorComponent } from '../../icon-selector/icon-selector.component';
import { HighlightPipe } from '../../../pipes/highlight.pipe';

import {
  FormFieldConfig,
  FormTemplateContext,
} from '../../../models/form-field.model';
import {
  hasProperty,
  isArray,
  isDefined,
  isEmpty,
  isFunction,
  isNullOrUndefined,
  isNumber,
  isObject,
  isSelectOption,
  isString,
} from '../../../utils';
import { ButtonModule } from 'primeng/button';
import { EventFilterFieldComponent } from '../event-filter-field/event-filter-field/event-filter-field.component';
import { AssetFilterFieldComponent } from '../asset-filter-field/asset-filter-field.component';
import { ZoneFilterFieldComponent } from '../zone-filter-field/zone-filter-field.component';
import { SplitButtonModule } from 'primeng/splitbutton';
import { MenuItem, TreeNode } from 'primeng/api';
import { ToggleSwitchModule } from 'primeng/toggleswitch';
import { EventFilterService } from '../../../services/event-filter.service';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { TranslateService } from '@ngx-translate/core';

interface ColorOption {
  label: string;
  value: string;
}

@Component({
  selector: 'app-dynamic-field',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    InputTextModule,
    InputNumberModule,
    MultiSelectModule,
    CheckboxModule,
    RadioButtonModule,
    TextareaModule,
    DatePickerModule,
    FileUploadModule,
    PasswordModule,
    InputMaskModule,
    ColorPickerModule,
    SliderModule,
    RatingModule,
    ChipModule,
    EditorModule,
    KeyFilterModule,
    MessageModule,
    ToggleButtonModule,
    KnobModule,
    SelectModule,
    ProgressSpinnerModule,
    AutoCompleteModule,
    ListboxModule,
    TreeSelectModule,
    TooltipModule,
    ButtonModule,
    EventFilterFieldComponent,
    AssetFilterFieldComponent,
    ZoneFilterFieldComponent,
    SplitButtonModule,
    FormsModule,
    ToggleSwitchModule,
    IconSelectorComponent,
    HighlightPipe,
    PopoverModule,
  ],
  templateUrl: './dynamic-field.component.html',
  styleUrl: './dynamic-field.component.scss',
})
export class DynamicFieldComponent implements OnInit {
  private readonly destroyRef = inject(DestroyRef);
  private readonly translate = inject(TranslateService);

  readonly field = input.required<FormFieldConfig>();
  readonly control = input.required<FormControl>();
  readonly customTemplate = input<TemplateRef<FormTemplateContext> | null>();
  fieldChange = output<{ field: FormFieldConfig; value: string | number }>();

  // --- Outputs for list actions ---
  readonly addItem = output<{ field: FormFieldConfig }>();
  readonly editItem = output<{
    field: FormFieldConfig;
    item: unknown;
    index: number;
  }>();
  readonly deleteItem = output<{ field: FormFieldConfig; index: number }>();

  private readonly formState = signal<{
    invalid: boolean;
    dirty: boolean;
    touched: boolean;
  }>({ invalid: false, dirty: false, touched: false });

  readonly fieldKey = computed(() => this.field().key);
  readonly fieldLabel = computed(() => this.field().label);
  readonly fieldType = computed(() => this.field().type);
  readonly fieldLayout = computed(() => this.field().layout);
  readonly fieldProps = computed(() => {
    const props = this.field().props;
    return isObject(props) ? props : {};
  });
  readonly treeNodeOptions = computed(() => this.field().treeNodeOptions);
  readonly fieldOptions = computed(() => {
    const options = this.field().options;
    return Array.isArray(options) ? options : [];
  });
  readonly isHorizontal = computed(() => this.fieldLayout() === 'horizontal');

  readonly isMultiValueField = computed(() => {
    const field = this.field();
    const props = field.props;

    if (field.type === 'multiselect') {
      return true;
    }

    if (field.type === 'autocomplete' && props?.multiple === true) {
      return true;
    }

    if (field.type === 'listbox' && props?.multiple === true) {
      return true;
    }

    if (field.type === 'treeselect') {
      const selectionMode = props?.selectionMode;
      return (
        selectionMode === 'checkbox' ||
        selectionMode === 'multiple' ||
        props?.multiple === true
      );
    }

    return false;
  });

  readonly multiSelectMaxLabels = computed(() => {
    const max = this.fieldProps()['maxSelectedLabels'];
    return isNumber(max) ? max : 3;
  });

  readonly multiSelectSelectedItemsLabel = computed(() => {
    const label = this.fieldProps()['selectedItemsLabel'];
    return isString(label) ? label : '{0} items selected';
  });

  readonly treeSelectDisplay = computed((): 'comma' | 'chip' => {
    const display = this.fieldProps()['display'];
    return display === 'comma' ? 'comma' : 'chip';
  });

  readonly listboxAllSelected = computed(() => {
    this.formState(); // re-evaluate when value changes
    const options = this.fieldOptions();
    const value = this.control().value;
    return (
      options.length > 0 &&
      Array.isArray(value) &&
      value.length === options.length
    );
  });
  readonly labelWidth = computed(() => {
    const field = this.field();
    return this.isHorizontal() &&
      isDefined(field.labelWidth) &&
      isString(field.labelWidth)
      ? field.labelWidth
      : '200px';
  });

  readonly showError = computed(() => {
    const state = this.formState();
    return state.invalid && (state.dirty || state.touched);
  });

  readonly errorMessage = computed(() => {
    const validations = this.field().validations;
    const errors = this.control().errors;
    if (!isObject(errors)) return '';

    if (!Array.isArray(validations)) {
      if (isDefined(errors['invalidTimeFormat']))
        return 'Invalid time format (HH:mm required)';
      return 'Invalid value';
    }

    const errorRule = validations.find(
      (v) => isDefined(v) && isString(v.name) && hasProperty(errors, v.name),
    );

    if (isDefined(errorRule) && isString(errorRule.message)) {
      return errorRule.message;
    }

    // Default fallback for common errors not explicitly in validations list
    if (isDefined(errors['invalidTimeFormat']))
      return 'Invalid time format (HH:mm required)';

    return 'Invalid value';
  });

  // Helper method to evaluate loading state (supports both boolean and function)
  readonly isFieldLoading = computed(() =>
    this.resolveLoadingState(this.field().loading),
  );

  // Helper method to evaluate autocomplete-specific loading state
  readonly isAutocompleteLoading = computed(() =>
    this.resolveLoadingState(this.field().autocompleteLoading),
  );

  readonly autocompleteEmptyMessage = computed(() =>
    this.isAutocompleteLoading()
      ? this.translate.instant('SHARED.COMMON.STATUS.LOADING') + '...'
      : (this.field().props?.emptyMessage ??
        this.translate.instant('SHARED.COMMON.STATUS.NO_RESULTS')),
  );

  private resolveLoadingState(
    loading: boolean | (() => boolean) | undefined,
  ): boolean {
    return typeof loading === 'function' ? loading() : loading === true;
  }

  readonly fieldClasses = computed(() => {
    const field = this.field();
    const baseClass = isString(field.inputStyleClass)
      ? field.inputStyleClass
      : 'w-full';

    const isInvalid = this.showError();
    const isDisabled =
      isDefined(field) &&
      ((hasProperty(field, 'disabled') && field.disabled === true) ||
        this.isFieldLoading() ||
        (hasProperty(field, 'readonly') && field.readonly === true));

    const classes = [];
    classes.push(baseClass);
    if (isInvalid) classes.push('ng-invalid', 'ng-dirty');
    if (isDisabled) classes.push('p-disabled');

    return classes.filter(isDefined).join(' ').trim();
  });

  readonly listItems = signal<
    {
      id: string;
      title?: string;
      display: string;
      icon?: string;
      iconStyle?: object;
      original: unknown;
    }[]
  >([]);
  readonly autocompleteSearchQuery = signal<string>('');
  readonly modalConfig = computed(() => this.field().props?.modalConfig);
  readonly listItemTemplate = computed(
    () => this.field().props?.listItemTemplate,
  );
  splitButtonTreeModel: MenuItem[] = [];

  // Signals for color picker enhancement
  private readonly defaultColorOptions: ColorOption[] = [
    { label: 'Black', value: '#000000' },
    { label: 'White', value: '#ffffff' },
    { label: 'Red', value: '#ff0000' },
    { label: 'Green', value: '#00ff00' },
    { label: 'Blue', value: '#0000ff' },
  ];
  readonly colorOptions: WritableSignal<ColorOption[]> = signal<ColorOption[]>(
    [],
  );
  selectedColor: WritableSignal<string | object | null> = signal<
    string | object | null
  >(null);
  manualColorInput = signal<string>('');
  filterService = inject(EventFilterService);

  // Internal FormControl for date picker to handle Date objects
  private readonly internalDateControl =
    signal<FormControl<Date | null> | null>(null);
  readonly activeDateControl = computed(() => {
    const isTimeOnly = this.field().props?.timeOnly ?? false;
    return isTimeOnly ? this.internalDateControl() : this.control();
  });
  private isUpdatingDateControl = false; // Prevent circular updates
  private _lastControlRef: FormControl | null = null;

  constructor() {
    // Effect to update form state (invalid, dirty, touched)
    effect((onCleanup) => {
      const control = this.control();
      if (isDefined(control)) {
        this.syncFormState(control);
        // Subscribe to status changes if not already done (handle potential re-creation)
        const statusSub = control.statusChanges
          .pipe(takeUntilDestroyed(this.destroyRef))
          .subscribe(() => this.syncFormState(control));
        const valueSub = control.valueChanges
          .pipe(takeUntilDestroyed(this.destroyRef))
          .subscribe((value) => this.handleControlValueChange(value, control));

        onCleanup(() => {
          statusSub.unsubscribe();
          valueSub.unsubscribe();
        });
      }
    });

    // Effect to update list items for modalList
    effect(() => {
      if (this.fieldType() === 'modalList') {
        const controlValue = this.control().value;
        const formatter = this.modalConfig()?.listItemFormatter;
        const items = isArray(controlValue) ? controlValue : [];

        if (isFunction(formatter)) {
          this.listItems.set(
            items.map((item, index) => ({
              ...formatter(item),
              original: item, // Keep original item data
              id: `${this.fieldKey()}-${index}`, // Generate unique ID for trackBy
            })),
          );
        } else {
          // Default formatting if no formatter provided
          this.listItems.set(
            items.map((item, index) => ({
              id: `${this.fieldKey()}-${index}`,
              display: isObject(item) ? JSON.stringify(item) : String(item),
              original: item,
            })),
          );
        }
      } else if (this.fieldType() === 'treeSplitButtonList') {
        const controlValue = this.control().value;
        const formatter = this.fieldProps().listItemFormatter;
        const items = isArray(controlValue) ? controlValue : [];

        if (isFunction(formatter)) {
          this.listItems.set(
            items.map((item, index) => ({
              ...formatter(item),
              original: item, // Keep original item data
              id: `${this.fieldKey()}-${index}`, // Generate unique ID for trackBy
            })),
          );
        }
      } else if (this.listItems().length > 0) {
        this.listItems.set([]);
      }
    });

    // Effect to build split button tree model
    effect(() => {
      const type = this.fieldType();
      const treeNodes: TreeNode[] = this.treeNodeOptions() ?? [];
      if (type === 'treeSplitButtonList') {
        this.splitButtonTreeModel = this.buildSplitButtonTreeModel(treeNodes);
      } else {
        this.splitButtonTreeModel = [];
      }
    });

    // Effect to sync selectedColor with control value for color picker
    effect(() => {
      const control = this.control();
      const type = this.fieldType();
      if (type === 'colorPicker') {
        const controlValue = control.value;
        if (!isEmpty(controlValue) && this.selectedColor() !== controlValue) {
          this.selectedColor.set(controlValue);
          this.manualColorInput.set(String(controlValue));

          // Ensure the control's value is in the dropdown options
          // Check if colorOptions has been initialized by ngOnInit
          const currentOpts = this.colorOptions();
          if (currentOpts.length > 0) {
            const exists = currentOpts.some(
              (opt) => opt.value === controlValue,
            );
            if (!exists) {
              this.colorOptions.update((options) => [
                ...options,
                { label: controlValue, value: controlValue },
              ]);
            }
          }
        } else if (controlValue === null && this.selectedColor() !== null) {
          this.selectedColor.set(null);
        }
      }
    });
    this.setupDateSyncEffect();
  }

  private syncFormState(control: FormControl): void {
    this.formState.set({
      invalid: control.invalid,
      dirty: control.dirty,
      touched: control.touched,
    });
  }

  private handleControlValueChange(value: unknown, control: FormControl): void {
    this.syncFormState(control);

    const fieldType = this.fieldType();
    this.triggerGenericOnChange(fieldType, value);
    this.syncListItems(fieldType);
    this.syncColorPickerValue(fieldType, control);
  }

  private triggerGenericOnChange(fieldType: string, value: unknown): void {
    const onChange = this.field().events?.onChange;
    if (!isFunction(onChange)) {
      return;
    }

    const hasExplicitHandler =
      fieldType === 'dropdown' || fieldType === 'autocomplete';
    if (!hasExplicitHandler) {
      onChange(value);
    }
  }

  private syncListItems(fieldType: string): void {
    if (fieldType !== 'modalList' && fieldType !== 'treeSplitButtonList') {
      if (this.listItems().length > 0) {
        this.listItems.set([]);
      }
      return;
    }

    const controlValue = this.control().value;
    const formatter =
      fieldType === 'modalList'
        ? this.modalConfig()?.listItemFormatter
        : this.fieldProps().listItemFormatter;
    const items = isArray(controlValue) ? controlValue : [];

    if (isFunction(formatter)) {
      this.listItems.set(
        items.map((item, index) => ({
          ...formatter(item),
          original: item,
          id: `${this.fieldKey()}-${index}`,
        })),
      );
      return;
    }

    if (fieldType === 'modalList') {
      this.listItems.set(
        items.map((item, index) => ({
          id: `${this.fieldKey()}-${index}`,
          display: isObject(item) ? JSON.stringify(item) : String(item),
          original: item,
        })),
      );
    }
  }

  private syncColorPickerValue(fieldType: string, control: FormControl): void {
    if (fieldType !== 'colorPicker') {
      return;
    }

    const colorVal = control.value as string | null;
    this.updateColorStateAndOptions(colorVal);
    if (isDefined(colorVal) && this.manualColorInput() !== colorVal) {
      this.manualColorInput.set(colorVal);
    }
  }

  ngOnInit(): void {
    if (this.field().type === 'colorPicker') {
      const propsColorOptions = this.field().props?.colorOptions;
      if (Array.isArray(propsColorOptions) && propsColorOptions.length > 0) {
        this.colorOptions.set([...propsColorOptions]);
      } else {
        this.colorOptions.set([...this.defaultColorOptions]);
      }

      const initialColor = this.control().value as string | null;
      if (isDefined(initialColor)) {
        this.manualColorInput.set(initialColor);
      }
      // Call the helper to set initial selectedColor and ensure option exists
      this.updateColorStateAndOptions(initialColor);
    }

    // Logic moved to effect for better reactivity and cleanup
  }

  private setupDateSyncEffect(): void {
    let internalSub: Subscription | null = null;
    let controlSub: Subscription | null = null;

    effect((onCleanup) => {
      const field = this.field();
      const control = this.control();

      if (!(field.type === 'date' && (field.props?.timeOnly ?? false))) {
        this.clearInternalDateControl();
        return;
      }

      const internal = this.ensureInternalDateControl();

      if (internalSub) internalSub.unsubscribe();
      if (controlSub) controlSub.unsubscribe();

      this.syncInitialTimeOnlyValue(control, internal);

      internalSub = internal.valueChanges.subscribe((dateValue) => {
        this.syncInternalDateToControl(dateValue, control, field);
      });

      controlSub = control.valueChanges.subscribe((stringValue) => {
        this.syncControlStringToInternalDate(stringValue, control, internal);
      });

      onCleanup(() => {
        if (internalSub) internalSub.unsubscribe();
        if (controlSub) controlSub.unsubscribe();
      });
    });
  }

  private ensureInternalDateControl(): FormControl<Date | null> {
    let internal = untracked(() => this.internalDateControl());
    if (!internal) {
      internal = new FormControl<Date | null>(null);
      this.internalDateControl.set(internal);
    }

    return internal;
  }

  private clearInternalDateControl(): void {
    if (untracked(() => this.internalDateControl())) {
      this.internalDateControl.set(null);
      this._lastControlRef = null;
    }
  }

  private syncInitialTimeOnlyValue(
    control: FormControl,
    internal: FormControl<Date | null>,
  ): void {
    if (untracked(() => this._lastControlRef) === control) {
      return;
    }

    this._lastControlRef = control;
    const val = control.value;
    if (typeof val === 'string' && /^\d{2}:\d{2}$/.test(val)) {
      const [h, m] = val.split(':').map(Number);
      const d = new Date();
      d.setHours(h, m, 0, 0);
      internal.setValue(d, { emitEvent: false });
    }
  }

  private syncInternalDateToControl(
    dateValue: Date | null,
    control: FormControl,
    field: FormFieldConfig,
  ): void {
    if (this.isUpdatingDateControl) return;

    this.isUpdatingDateControl = true;
    try {
      if (dateValue instanceof Date) {
        const hours = dateValue.getHours().toString().padStart(2, '0');
        const minutes = dateValue.getMinutes().toString().padStart(2, '0');
        const timeString = `${hours}:${minutes}`;

        if (control.value !== timeString) {
          control.setValue(timeString);
          control.markAsDirty();
          control.markAsTouched();
          this.fieldChange.emit({ field, value: timeString });
        }
      } else if (control.value !== null) {
        control.setValue(null);
        control.markAsDirty();
      }
    } finally {
      this.isUpdatingDateControl = false;
    }
  }

  private syncControlStringToInternalDate(
    stringValue: unknown,
    control: FormControl,
    internal: FormControl<Date | null>,
  ): void {
    if (this.isUpdatingDateControl) return;

    this.isUpdatingDateControl = true;
    try {
      if (typeof stringValue === 'string' && stringValue.trim() !== '') {
        this.handleTimeStringUpdate(stringValue, control, internal);
        return;
      }

      if (stringValue === null && internal.value !== null) {
        internal.setValue(null, { emitEvent: false });
      }
    } finally {
      this.isUpdatingDateControl = false;
    }
  }

  private handleTimeStringUpdate(
    stringValue: string,
    control: FormControl,
    internal: FormControl<Date | null>,
  ): void {
    const timePattern = /^\d{2}:\d{2}$/;
    if (!timePattern.test(stringValue)) {
      control.setErrors({
        ...control.errors,
        invalidTimeFormat: true,
      });
      return;
    }

    const [h, m] = stringValue.split(':').map(Number);
    this.clearInvalidTimeFormatError(control);

    const current = internal.value;
    if (current?.getHours() === h && current.getMinutes() === m) {
      return;
    }

    const date = new Date();
    date.setHours(h, m, 0, 0);
    internal.setValue(date, { emitEvent: false });
  }

  private clearInvalidTimeFormatError(control: FormControl): void {
    if (!control.hasError('invalidTimeFormat')) {
      return;
    }

    const errors = { ...control.errors };
    delete errors['invalidTimeFormat'];
    control.setErrors(Object.keys(errors).length ? errors : null);
  }

  private buildSplitButtonTreeModel(treeNodes: TreeNode[]): MenuItem[] {
    const buildMenuItemsWithCommands = (nodes: TreeNode[]): MenuItem[] =>
      nodes.map((node) => {
        const menuItem: MenuItem = {
          label: node.label,
          icon: node.icon,
          data: node.data ?? node,
        };
        if (Array.isArray(node.children) && node.children.length > 0) {
          menuItem.items = buildMenuItemsWithCommands(node.children);
        } else if (node.selectable !== false) {
          menuItem.command = () => this.handleSplitButtonTreeItemSelect(node);
        }
        return menuItem;
      });
    return buildMenuItemsWithCommands(treeNodes);
  }

  trackByOption(_index: number, option: unknown): string | number {
    if (
      isSelectOption(option) &&
      (isString(option.value) || isNumber(option.value))
    ) {
      return option.value;
    }
    return String(option);
  }

  onFileSelect(event: unknown): void {
    if (
      isDefined(event) &&
      isObject(event) &&
      hasProperty(event, 'files') &&
      Array.isArray(event['files']) &&
      event['files'].length > 0
    ) {
      this.control().setValue(event['files'][0]);
    }
  }

  getToggleButtonLabel(value: unknown): string {
    const onLabelValue = isDefined(this.field().props?.['onLabel'])
      ? String(this.field().props?.['onLabel'])
      : 'Yes';
    const offLabelValue = isDefined(this.field().props?.['offLabel'])
      ? String(this.field().props?.['offLabel'])
      : 'No';
    return typeof value === 'boolean' && value ? onLabelValue : offLabelValue;
  }

  onDropdownChange(event: SelectChangeEvent): void {
    this.fieldChange.emit({ field: this.field(), value: event.value });

    const onChangeHandler = this.field().events?.onChange;
    if (isFunction(onChangeHandler)) {
      onChangeHandler(event.value);
    }
  }

  triggerAddItem(): void {
    if (this.fieldType() === 'modalList') {
      this.addItem.emit({ field: this.field() });
    }
  }

  triggerEditItem(
    item: { id: string; display: string; icon?: string; original: unknown },
    index: number,
  ): void {
    if (this.fieldType() === 'modalList') {
      this.editItem.emit({ field: this.field(), item: item.original, index });
    }
  }

  triggerDeleteItem(index: number): void {
    if (this.fieldType() === 'modalList') {
      // Optional: Add confirmation dialog here
      this.deleteItem.emit({ field: this.field(), index });
    }
  }

  handleSplitButtonTreeItemSelect(selectedNode: TreeNode): void {
    const fieldConfig = this.field();
    const control = this.control();
    let newItem: unknown;

    const transformer = fieldConfig.props?.transformTreeNodeToItem as (
      node: TreeNode,
    ) => unknown;

    if (isFunction(transformer)) {
      newItem = transformer(selectedNode);
    } else {
      newItem = selectedNode.data ?? selectedNode; // Default to node data or the node itself
    }

    const currentItems = Array.isArray(control.value) ? [...control.value] : [];
    currentItems.push(newItem);

    control.setValue(currentItems);
    control.markAsDirty();
    control.updateValueAndValidity();
    // listItems signal will update via the existing effect watching control.valueChanges
  }

  handleSplitButtonListItemDelete(index: number): void {
    const control = this.control();
    const currentItems = Array.isArray(control.value) ? [...control.value] : [];
    currentItems.splice(index, 1);
    control.setValue(currentItems);
    control.markAsDirty();
    control.updateValueAndValidity();
  }

  // Helper for template
  getAddButtonLabel(): string {
    const fieldType = this.fieldType();
    const props = this.field().props;

    if (fieldType === 'modalList') {
      return this.modalConfig()?.addButtonLabel ?? 'Add Item';
    }
    if (fieldType === 'treeSplitButtonList') {
      return (props?.addButtonLabel as string) ?? 'Add from Tree';
    }
    return 'Add Item'; // Generic fallback
  }

  handleAutocompleteSearch(query: string): void {
    this.autocompleteSearchQuery.set(query);
    const onSearch = this.field().events?.onSearch;
    if (isFunction(onSearch)) {
      onSearch(query);
    }
  }

  /**
   * Handle changes to the autocomplete selection.
   * If the selected value is an object, it stringifies it before passing to onChange handler.
   * This ensures that complex objects can be handled properly by the parent form.
   * @param event The selection change event from the autocomplete component.
   * @returns void
   */
  onAutocompleteChange(event: { value: unknown }): void {
    // Handle autocomplete selection changes
    const onChange = this.field().events?.onChange;
    if (isFunction(onChange)) {
      const value = event.value;
      if (value !== null && typeof value === 'object') {
        // If it's an object, stringify it so the onChange handler can parse it
        onChange(JSON.stringify(value));
      } else if (typeof value === 'string' || typeof value === 'number') {
        onChange(String(value));
      } else {
        onChange('');
      }
    }
  }

  onAutocompleteValueChange(): void {
    // Handle when autocomplete value changes (for multiple/chips mode)
    // Mark the control as dirty to enable save button
    const control = this.control();
    if (!control.dirty) {
      control.markAsDirty();
    }
  }

  onAutocompleteBlur(event: Event): void {
    // When autocomplete loses focus, commit any pending text as a tag
    const target = event.target as HTMLInputElement;
    const pendingValue = target?.value?.trim();
    const isMultiple = this.field().props?.multiple === true;

    if (pendingValue && isMultiple) {
      const control = this.control();
      const currentValue = Array.isArray(control.value) ? control.value : [];

      // Only add if it's not already in the list
      if (!currentValue.includes(pendingValue)) {
        control.setValue([...currentValue, pendingValue]);
        control.markAsDirty();
      }

      // Clear the input
      target.value = '';
    }
  }

  private updateColorStateAndOptions(colorValue: string | null): void {
    this.selectedColor.set(colorValue);

    if (typeof colorValue === 'string' && !isEmpty(colorValue)) {
      // Ensure the control's value is in the dropdown options
      const currentOpts = this.colorOptions();
      // Check if colorOptions has been initialized (it should be by ngOnInit or subsequent updates)
      if (currentOpts.length > 0 || this.field().type === 'colorPicker') {
        // Ensure we try to add even if default list was empty
        const exists = currentOpts.some((opt) => opt.value === colorValue);
        if (!exists) {
          this.colorOptions.update((options) => [
            ...options,
            { label: colorValue, value: colorValue }, // Use colorValue as label for simplicity
          ]);
        }
      }
    }
  }

  onColorSelect(colorValue: string): void {
    const control = this.control();
    control.setValue(colorValue);
    control.markAsDirty();
    control.updateValueAndValidity();
  }

  onColorPickerChange(
    event: ColorPickerChangeEvent,
    control: AbstractControl,
  ): void {
    const newColor = String(event.value);
    if (isDefined(control)) {
      control.setValue(newColor);
      this.manualColorInput.set(newColor);
      this.updateColorStateAndOptions(newColor);
    }
  }

  onManualColorInputChange(value: string): void {
    this.manualColorInput.set(value);
    const control = this.control();
    if (!isDefined(control) || !value) return;

    const isValidHex =
      (value.length === 7 || value.length === 4) && value.startsWith('#');
    const isValidRgb = value.startsWith('rgb');

    if (isValidHex || isValidRgb) {
      control.setValue(value);
      control.markAsDirty();
      control.updateValueAndValidity();
      this.updateColorStateAndOptions(value);
    }
  }

  getDateControl(): FormControl {
    return (this.activeDateControl() as FormControl) ?? this.control();
  }

  getSuggestions(): unknown[] {
    const suggestions = this.field().props?.suggestions;
    if (isFunction(suggestions)) {
      return suggestions() ?? [];
    }
    return suggestions ?? [];
  }

  getAutocompleteDisplayText(option: unknown): string {
    if (isNullOrUndefined(option)) return '';

    const field = this.field();
    const itemDisplayFormatter = field.props?.itemDisplayFormatter;

    if (typeof itemDisplayFormatter === 'function') {
      return itemDisplayFormatter(option);
    }

    const optionLabel = field.props?.field;

    if (isDefined(optionLabel)) {
      const value = (option as Record<string, unknown>)[optionLabel] as string;
      return String(value ?? '');
    }

    if (isObject(option)) {
      if (hasProperty(option, 'label') && isDefined(option['label'])) {
        return String(option['label']);
      }
      if (hasProperty(option, 'name') && isDefined(option['name'])) {
        return String(option['name']);
      }
      if (hasProperty(option, 'value') && isDefined(option['value'])) {
        return String(option['value']);
      }

      return '';
    }

    if (isString(option) || isNumber(option) || typeof option === 'boolean') {
      return String(option);
    }

    if (option instanceof Date) {
      return option.toISOString();
    }

    return '';
  }
}
