export function findIconEntry(name: string): IconEntry | undefined {
  return MATERIAL_ICONS.find((e) => e.name === name);
}

@Component({
  selector: 'app-icon-selector',
  imports: [
    CommonModule,
    FormsModule,
    ButtonModule,
    DialogModule,
    InputTextModule,
    ScrollPanelModule,
    IconField,
    InputIcon,
  ],
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: IconSelectorComponent,
      multi: true,
    },
  ],
  templateUrl: './icon-selector.component.html',
  styleUrl: './icon-selector.component.scss',
})
export class IconSelectorComponent implements ControlValueAccessor {
  // Input properties
  readonly placeholder = input<string>('Select an icon');
  readonly disabled = input<boolean>(false);

  // Output events
  readonly iconChange = output<string | null>();

  // Internal state
  readonly dialogVisible = signal<boolean>(false);
  readonly searchTerm = signal<string>('');
  readonly value = signal<string | null>(null);

  // Available icons
  readonly availableIcons = signal<IconEntry[]>(MATERIAL_ICONS);

  // Filtered icons based on search (name + keywords)
  readonly filteredIcons = computed(() => {
    const search = this.searchTerm().toLowerCase().trim();
    if (!search) return this.availableIcons();
    return this.availableIcons().filter(
      (entry) =>
        entry.name.toLowerCase().includes(search) ||
        (entry.keywords?.some((kw) => kw.toLowerCase().includes(search)) ??
          false),
    );
  });

  readonly selectedEntry = computed(() =>
    this.availableIcons().find((e) => e.name === this.value()) ?? null,
  );

  // ControlValueAccessor implementation
  private onChange = (_value: string | null) => {};
  private onTouched = () => {};

  showDialog(): void {
    if (!this.disabled()) {
      this.dialogVisible.set(true);
      this.searchTerm.set('');
    }
  }

  selectIcon(icon: string): void {
    this.value.set(icon);
    this.onChange(icon);
    this.onTouched();
    this.iconChange.emit(icon);
    this.dialogVisible.set(false);
  }

  clearSelection(): void {
    this.value.set(null);
    this.onChange(null);
    this.onTouched();
    this.iconChange.emit(null);
  }

  // ControlValueAccessor methods
  writeValue(value: string | null): void {
    this.value.set(value);
  }

  registerOnChange(fn: (value: string | null) => void): void {
    this.onChange = fn;
  }

  registerOnTouched(fn: () => void): void {
    this.onTouched = fn;
  }

  setDisabledState(_isDisabled: boolean): void {
    // Handle disabled state if needed
  }
}
